1	export interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	}
5	
6	export interface QuoteInput {
7	  items: QuoteItem[];
8	  customer: { yearsWithMHPCO: number };
9	  isFollowUp: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	const BLOCK_OF_3_PREMIUM = 60;
15	const CURSED_SURCHARGE_RATE = 0.5;
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	export function quote(input: QuoteInput): number {
27	  let policyBase = 0;
28	
29	  const itemTypeCounts: Record<string, number> = {};
30	  for (const item of input.items) {
31	    itemTypeCounts[item.type] = (itemTypeCounts[item.type] || 0) + 1;
32	  }
33	
34	  for (const [type, count] of Object.entries(itemTypeCounts)) {
35	    if (count === 3) {
36	      policyBase += BLOCK_OF_3_PREMIUM;
37	    } else {
38	      policyBase += count * BASE_PREMIUM[type];
39	    }
40	  }
41	
42	  let itemSurcharges = 0;
43	  for (const item of input.items) {
44	    if (item.cursed) {
45	      itemSurcharges += BASE_PREMIUM[item.type] * CURSED_SURCHARGE_RATE;
46	    }
47	  }
48	
49	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
50	  const policyPremium = policyBase + itemSurcharges + firstInsuranceSurcharge;
51	  return Math.ceil(policyPremium + PROCESSING_FEE);
52	}
